`timescale 1ns / 1ps

`include "uart_defines.vh"

module uart_rfifo (
   clk,
   wb_rst_i,
   data_in,
   data_out,
   // Control signals
   push,  // push strobe, active high
   pop,  // pop strobe, active high
   // status signals
   overrun,
   count,
   error_bit,
   fifo_reset,
   reset_status
);


   // FIFO parameters
   parameter fifo_width = `UART_FIFO_WIDTH;
   parameter fifo_depth = `UART_FIFO_DEPTH;
   parameter fifo_pointer_w = `UART_FIFO_POINTER_W;
   parameter fifo_counter_w = `UART_FIFO_COUNTER_W;

   input clk;
   input wb_rst_i;
   input push;
   input pop;
   input [fifo_width-1:0] data_in;
   input fifo_reset;
   input reset_status;

   output [fifo_width-1:0] data_out;
   output overrun;
   output [fifo_counter_w-1:0] count;
   output error_bit;

   genvar i;

   wire [    fifo_width-1:0] data_out;
   wire [               7:0] data8_out;
   // flags FIFO
   reg  [               2:0] fifo                    [fifo_depth];

   // FIFO pointers
   reg  [fifo_pointer_w-1:0] top;
   reg  [fifo_pointer_w-1:0] bottom;

   reg  [fifo_counter_w-1:0] count;
   reg                       overrun;

   wire [fifo_pointer_w-1:0] top_plus_1 = top + 1'b1;

   raminfr #(
      .addr_width(fifo_pointer_w),
      .data_width(8),
      .depth     (fifo_depth)
   ) rfifo (
      .clk (clk),
      .we  (push),
      .a   (top),
      .dpra(bottom),
      .di  (data_in[fifo_width-1:fifo_width-8]),
      .dpo (data8_out)
   );

   always @(posedge clk or posedge wb_rst_i)  // synchronous FIFO
      begin
      // Cannot check '(wb_rst_i | fifo_reset)' because of Quartus issue: https://www.intel.com/content/www/us/en/programmable/quartushelp/18.1/index.htm#msgs/msgs/evrfx_veri_if_condition_does_not_match_sensitivity_list_edge.htm
      if (wb_rst_i) begin
         top    <= #1 0;
         bottom <= #1 0;
         count  <= #1 0;
      end else if (fifo_reset) begin
         top    <= #1 0;
         bottom <= #1 0;
         count  <= #1 0;
      end else begin
         case ({
            push, pop
         })
            2'b10:
            if (count < fifo_depth)  // overrun condition
                begin
               top       <= #1 top_plus_1;
               fifo[top] <= #1 data_in[2:0];
               count     <= #1 count + 1'b1;
            end
            2'b01:
            if (count > 0) begin
               fifo[bottom] <= #1 0;
               bottom       <= #1 bottom + 1'b1;
               count        <= #1 count - 1'b1;
            end
            2'b11: begin
               bottom    <= #1 bottom + 1'b1;
               top       <= #1 top_plus_1;
               fifo[top] <= #1 data_in[2:0];
            end
            default: ;
         endcase
      end
   end  // always

   always @(posedge clk or posedge wb_rst_i)  // synchronous FIFO
       begin
      if (wb_rst_i) overrun <= #1 1'b0;
      else if (fifo_reset | reset_status) overrun <= #1 1'b0;
      else if (push & ~pop & (count == fifo_depth)) overrun <= #1 1'b1;
   end  // always


   // please note though that data_out is only valid one clock after pop signal
   assign data_out = {data8_out, fifo[bottom]};

   // Additional logic for detection of error conditions (parity and framing) inside the FIFO
   // for the Line Status Register bit 7

   // a 1 is returned if any of the error bits in the fifo is 1
   wire [3*fifo_depth-1:0] error_bits;
   generate
      for (i = 0; i < fifo_depth; i = i + 1) begin : gen_error_bits
         assign error_bits[i*3+:3] = fifo[i][2:0];
      end
   endgenerate
   assign error_bit = |error_bits;


endmodule

