      .addr_width(fifo_pointer_w),
      .data_width(8),
      .depth     (fifo_depth)
   ) rfifo (
      .clk (clk),
      .we  (push),
      .a   (top),
      .dpra(bottom),
      .di  (data_in[fifo_width-1:fifo_width-8]),
      .dpo (data8_out)
