         bottom <= #1 0;
         count  <= #1 0;
         error_count <= #1 0;
         rfifo_flags <= #1 0;
      end else if (fifo_reset) begin
         top    <= #1 0;
         bottom <= #1 0;
         count  <= #1 0;
         error_count <= #1 0;
         rfifo_flags <= #1 0;
