               fifo[bottom] <= #1 0;
               bottom       <= #1 bottom + 1'b1;
               count        <= #1 count - 1'b1;
               if(|rfifo_flags) begin
                   error_count <= #1 error_count - 1'b1;
               end
               rfifo_flags <= #1 fifo[bottom + 1'b1];
